import{_ as l,o as i,c as e,a9 as r}from"./chunks/framework.STMWz9Nm.js";const p=JSON.parse('{"title":"性能优化与常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"语言/java/11-ElasticSearch学习/06-性能优化与常见问题.md","filePath":"语言/java/11-ElasticSearch学习/06-性能优化与常见问题.md","lastUpdated":1776149370000}'),t={name:"语言/java/11-ElasticSearch学习/06-性能优化与常见问题.md"};function h(_,a,n,s,c,d){return i(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="性能优化与常见问题" tabindex="-1">性能优化与常见问题 <a class="header-anchor" href="#性能优化与常见问题" aria-label="Permalink to “性能优化与常见问题”">​</a></h1><h2 id="_1-这是什么" tabindex="-1">1. 这是什么 <a class="header-anchor" href="#_1-这是什么" aria-label="Permalink to “1. 这是什么”">​</a></h2><p>ES 性能优化关注查询、写入、分片、mapping 和资源使用之间的整体平衡。<br> 常见问题通常不是单点故障，而是设计和负载共同作用的结果。</p><h2 id="_2-为什么重要" tabindex="-1">2. 为什么重要 <a class="header-anchor" href="#_2-为什么重要" aria-label="Permalink to “2. 为什么重要”">​</a></h2><p>ElasticSearch 一旦成为核心搜索服务，性能波动会直接影响用户体验。<br> 掌握优化思路，才能把搜索系统稳定运行起来。</p><h2 id="_3-核心内容" tabindex="-1">3. 核心内容 <a class="header-anchor" href="#_3-核心内容" aria-label="Permalink to “3. 核心内容”">​</a></h2><ul><li>查询慢</li><li>写入慢</li><li>大聚合</li><li>mapping 爆炸</li><li>小分片过多</li><li>热点节点问题</li></ul><h2 id="_4-学习重点" tabindex="-1">4. 学习重点 <a class="header-anchor" href="#_4-学习重点" aria-label="Permalink to “4. 学习重点”">​</a></h2><ul><li>理解 ES 优化往往从模型和查询设计开始</li><li>理解性能问题常常是资源分布不均和请求模型失衡</li><li>理解治理要结合监控和压测</li></ul><h2 id="_5-常见问题" tabindex="-1">5. 常见问题 <a class="header-anchor" href="#_5-常见问题" aria-label="Permalink to “5. 常见问题”">​</a></h2><ul><li>过度依赖硬件扩容</li><li>聚合查询过重但缺乏限流</li><li>索引设计不合理导致后续无法优化</li></ul><h2 id="_6-练习建议" tabindex="-1">6. 练习建议 <a class="header-anchor" href="#_6-练习建议" aria-label="Permalink to “6. 练习建议”">​</a></h2><ul><li>总结一份 ES 性能巡检清单</li><li>复盘一个典型慢查询场景</li><li>比较不同建模方式对性能的影响</li></ul><h2 id="_7-自测问题" tabindex="-1">7. 自测问题 <a class="header-anchor" href="#_7-自测问题" aria-label="Permalink to “7. 自测问题”">​</a></h2><ul><li>ES 性能问题通常会从哪些维度排查</li><li>为什么索引模型对性能影响很大</li><li>小分片过多为什么是经典问题</li></ul>',15)])])}const m=l(t,[["render",h]]);export{p as __pageData,m as default};
